import { useEffect, useState } from 'react';
import { Plus, Pencil, Trash2, Users, Search } from 'lucide-react';
import { userService } from '../services/api';
import { Modal, FormField, ConfirmDialog, DataTable, EmptyState, PageLoader } from '../components/UI';
import toast from 'react-hot-toast';

// ─── User Form Modal ───────────────────────────────────────
const UserModal = ({ isOpen, onClose, onSaved, editUser }) => {
  const isEdit = !!editUser;
  const [form, setForm]   = useState({ name: '', email: '', password: '' });
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (editUser) setForm({ name: editUser.name, email: editUser.email, password: '' });
    else setForm({ name: '', email: '', password: '' });
  }, [editUser, isOpen]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      if (isEdit) {
        await userService.update(editUser.id, { name: form.name, email: form.email });
        toast.success('Cập nhật user thành công!');
      } else {
        await userService.create(form);
        toast.success('Tạo user thành công!');
      }
      onSaved();
      onClose();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Có lỗi xảy ra!');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={isEdit ? 'Sửa User' : 'Thêm User mới'}>
      <form onSubmit={handleSubmit} className="space-y-4">
        <FormField label="Họ tên" required>
          <input className="input-field" placeholder="Nguyễn Văn A" value={form.name}
            onChange={e => setForm(f => ({ ...f, name: e.target.value }))} required />
        </FormField>
        <FormField label="Email" required>
          <input type="email" className="input-field" placeholder="user@example.com" value={form.email}
            onChange={e => setForm(f => ({ ...f, email: e.target.value }))} required />
        </FormField>
        {!isEdit && (
          <FormField label="Mật khẩu" required>
            <input type="password" className="input-field" placeholder="Ít nhất 6 ký tự" value={form.password}
              onChange={e => setForm(f => ({ ...f, password: e.target.value }))} required />
          </FormField>
        )}
        <div className="flex gap-3 justify-end pt-2">
          <button type="button" onClick={onClose} className="btn-secondary">Hủy</button>
          <button type="submit" disabled={loading} className="btn-primary">
            {loading ? 'Đang lưu...' : isEdit ? 'Cập nhật' : 'Tạo mới'}
          </button>
        </div>
      </form>
    </Modal>
  );
};

// ═══════════════════════════════════════════════════════════
// USERS PAGE
// ═══════════════════════════════════════════════════════════
export const UsersPage = () => {
  const [users, setUsers]       = useState([]);
  const [loading, setLoading]   = useState(true);
  const [search, setSearch]     = useState('');
  const [modal, setModal]       = useState(false);
  const [editUser, setEditUser] = useState(null);
  const [deleteId, setDeleteId] = useState(null);
  const [deleting, setDeleting] = useState(false);

  const load = async () => {
    try {
      const res = await userService.getAll();
      setUsers(res.data);
    } catch (err) {
      toast.error('Không tải được danh sách users!');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { load(); }, []);

  const handleEdit = (user) => { setEditUser(user); setModal(true); };
  const handleAdd  = ()     => { setEditUser(null); setModal(true); };

  const handleDelete = async () => {
    setDeleting(true);
    try {
      await userService.delete(deleteId);
      toast.success('Xóa user thành công!');
      setDeleteId(null);
      load();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Xóa thất bại!');
    } finally {
      setDeleting(false);
    }
  };

  const filtered = users.filter(u =>
    u.name.toLowerCase().includes(search.toLowerCase()) ||
    u.email.toLowerCase().includes(search.toLowerCase())
  );

  if (loading) return <PageLoader />;

  return (
    <div className="space-y-6 animate-slide-up">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-slate-100">Quản lý Users</h1>
          <p className="text-slate-500 mt-1">{users.length} tài khoản trong hệ thống</p>
        </div>
        <button onClick={handleAdd} className="btn-primary">
          <Plus size={18} /> Thêm User
        </button>
      </div>

      {/* Table */}
      <div className="card">
        {/* Search */}
        <div className="relative mb-6">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
          <input
            className="input-field pl-10"
            placeholder="Tìm theo tên hoặc email..."
            value={search}
            onChange={e => setSearch(e.target.value)}
          />
        </div>

        <DataTable
          headers={['#', 'Họ tên', 'Email', 'Ngày tạo', 'Thao tác']}
          empty={
            <tr><td colSpan={5}>
              <EmptyState icon={Users} title="Không có user nào" desc="Thêm user đầu tiên để bắt đầu" />
            </td></tr>
          }
        >
          {filtered.map((user, i) => (
            <tr key={user.id} className="table-row">
              <td className="py-3 px-4 text-slate-500 text-sm font-mono">{i + 1}</td>
              <td className="py-3 px-4">
                <div className="flex items-center gap-3">
                  <div className="w-8 h-8 rounded-lg bg-brand-600/20 flex items-center justify-center text-brand-400 text-sm font-bold">
                    {user.name[0]?.toUpperCase()}
                  </div>
                  <span className="text-slate-200 font-medium">{user.name}</span>
                </div>
              </td>
              <td className="py-3 px-4 text-slate-400 text-sm">{user.email}</td>
              <td className="py-3 px-4 text-slate-500 text-sm">
                {new Date(user.createdAt).toLocaleDateString('vi-VN')}
              </td>
              <td className="py-3 px-4">
                <div className="flex items-center gap-2">
                  <button onClick={() => handleEdit(user)} className="p-1.5 text-slate-400 hover:text-brand-400 hover:bg-brand-400/10 rounded-lg transition-all">
                    <Pencil size={15} />
                  </button>
                  <button onClick={() => setDeleteId(user.id)} className="p-1.5 text-slate-400 hover:text-red-400 hover:bg-red-400/10 rounded-lg transition-all">
                    <Trash2 size={15} />
                  </button>
                </div>
              </td>
            </tr>
          ))}
        </DataTable>
      </div>

      <UserModal isOpen={modal} onClose={() => setModal(false)} onSaved={load} editUser={editUser} />
      <ConfirmDialog
        isOpen={!!deleteId}
        onClose={() => setDeleteId(null)}
        onConfirm={handleDelete}
        loading={deleting}
        title="Xóa User"
        message="Bạn có chắc muốn xóa user này? Hành động này không thể hoàn tác."
      />
    </div>
  );
};
